import React, { useState } from 'react';
import { motion } from 'framer-motion';
import axios from 'axios';

const Dashboard = () => {
  const [preview, setPreview] = useState(null);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    setPreview(URL.createObjectURL(file));
    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);

    try {
      const res = await axios.post('http://localhost:5000/analyze', formData);
      setData(res.data);
    } catch (err) {
      alert("Network Error: Ensure the Flask server is running on port 5000.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '40px', backgroundColor: '#F5F7FA', minHeight: '100vh', fontFamily: 'sans-serif' }}>
      <header style={{ marginBottom: '30px' }}>
        <h1 style={{ color: '#1E88E5', margin: 0 }}>NeuroScanAI Diagnostic Hub</h1>
        <p style={{ color: '#64748b' }}>Precision Brain Tumor Segmentation System</p>
      </header>

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '30px' }}>
        {/* Comparison Section */}
        <div style={{ background: 'white', padding: '30px', borderRadius: '30px', boxShadow: '0 20px 50px rgba(0,0,0,0.05)' }}>
          <div style={{ marginBottom: '20px' }}>
             <input type="file" onChange={handleUpload} style={{ display: 'block', marginBottom: '10px' }} />
             {loading && <p style={{ color: '#1E88E5', fontWeight: 'bold' }}>AI INFERENCE IN PROGRESS...</p>}
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', backgroundColor: '#111', padding: '15px', borderRadius: '20px' }}>
            <div style={{ position: 'relative' }}>
              {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px' }} alt="Original" />}
              <span style={{ position: 'absolute', top: '10px', left: '10px', background: 'rgba(0,0,0,0.5)', color: 'white', padding: '2px 8px', fontSize: '10px', borderRadius: '4px' }}>ORIGINAL MRI</span>
            </div>

            <div style={{ position: 'relative', minHeight: '200px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              {preview && <img src={preview} style={{ width: '100%', borderRadius: '10px', opacity: 0.8 }} alt="Base" />}
              {data?.mask && (
                <motion.img 
                  initial={{ opacity: 0 }} 
                  animate={{ opacity: 0.7 }} 
                  src={data.mask} 
                  style={{ 
                    position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', 
                    objectFit: 'contain', filter: 'hue-rotate(90deg) saturate(20) brightness(1.2)' 
                  }} 
                />
              )}
              <span style={{ position: 'absolute', top: '10px', left: '10px', background: '#1E88E5', color: 'white', padding: '2px 8px', fontSize: '10px', borderRadius: '4px' }}>AI SEGMENTATION</span>
            </div>
          </div>
        </div>

        {/* Confidence Section */}
        <div style={{ spaceY: '20px' }}>
          <div style={{ background: '#1E88E5', color: 'white', padding: '40px', borderRadius: '30px', textAlign: 'center' }}>
            <p style={{ fontSize: '0.8rem', opacity: 0.8, textTransform: 'uppercase' }}>Inference Confidence</p>
            <h2 style={{ fontSize: '4rem', margin: '10px 0' }}>{data ? (data.confidence * 100).toFixed(1) : '00.0'}%</h2>
            <div style={{ height: '8px', background: 'rgba(255,255,255,0.2)', borderRadius: '4px', overflow: 'hidden' }}>
              <motion.div initial={{ width: 0 }} animate={{ width: data ? `${data.confidence * 100}%` : 0 }} style={{ height: '100%', background: 'white' }} />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
